% --- Route-F Mathlib dependency anchors (ingredients of the G1-core descent below) ---

\begin{lemma}[Qcqs lemma: structure-sheaf sections on a basic open localize]
  \label{lem:isLocalization_basicOpen_of_qcqs_mathlib}
  \lean{AlgebraicGeometry.isLocalization_basicOpen_of_qcqs}
  \mathlibok
  \textit{Provided by Mathlib
  (\texttt{Mathlib.AlgebraicGeometry.Morphisms.QuasiSeparated}); the structure-sheaf
  template for the module descent below.}
  Let \(X\) be a scheme, \(U \subseteq X\) a quasi-compact and quasi-separated open, and
  \(f \in \Gamma(X, U)\). Then the restriction \(\Gamma(X, U) \to \Gamma(X, D(f))\) exhibits
  \(\Gamma(X, D(f))\) as the localization \(\Gamma(X,U)_f\); that is, it is
  \(\mathrm{IsLocalization.Away}\,f\). Mathlib assembles this from the three pointwise axioms of
  \(\mathrm{IsLocalization.Away}\) by compact-open induction and sheaf gluing, without constructing
  an equalizer object and without invoking flatness; \cref{lem:qcoh_affine_section_localization} is
  its module analogue.
\end{lemma}

\begin{lemma}[The three-field localized-module predicate]
  \label{lem:isLocalizedModule_constructor_mathlib}
  \lean{IsLocalizedModule}
  \mathlibok
  \textit{Provided by Mathlib (\texttt{Mathlib.Algebra.Module.LocalizedModule.Basic}).}
  For a submonoid \(S \subseteq R\) and an \(R\)-linear map \(g : M \to M'\), the predicate
  \(\mathrm{IsLocalizedModule}\,S\,g\) is the conjunction of three pointwise statements:
  \emph{(map\_units)} each \(s \in S\) acts invertibly on \(M'\);
  \emph{(surj)} every element of \(M'\) equals \(s^{-1}\,g(m)\) for some \(s \in S\), \(m \in M\); and
  \emph{(exists\_of\_eq)} if \(g(m_1) = g(m_2)\) then \(s\,m_1 = s\,m_2\) for some \(s \in S\).
  Supplying these three fields constructs \(\mathrm{IsLocalizedModule}\,S\,g\).
\end{lemma}

\begin{lemma}[A section restricted to its non-vanishing locus is a unit]
  \label{lem:isUnit_res_basicOpen_mathlib}
  \lean{AlgebraicGeometry.RingedSpace.isUnit_res_basicOpen}
  \mathlibok
  \textit{Provided by Mathlib (\texttt{Mathlib.Geometry.RingedSpace.Basic}).}
  Let \(X\) be a ringed space, \(U\) an open, and \(f \in \Gamma(X, U)\). Then the restriction of
  \(f\) to the basic open \(D(f) = X.\mathrm{basicOpen}\,f\) is a unit of the ring
  \(\Gamma(X, D(f))\).
\end{lemma}

\begin{lemma}[A presentation makes the $\widetilde{(-)}$-counit an isomorphism]
  \label{lem:isIso_fromTildeΓ_of_presentation_mathlib}
  \lean{AlgebraicGeometry.isIso_fromTildeΓ_of_presentation}
  \mathlibok
  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Tilde}).}
  Let \(M\) be a sheaf of modules on \(\Spec R\) equipped with a presentation (a
  cokernel-of-free-modules description). Then the counit
  \(M.\mathrm{fromTildeΓ} : \widetilde{\Gamma(M,\top)} \to M\) is an isomorphism. Applied on an
  affine \(\Spec R_g\) this identifies \(M\) with \(\widetilde{N_g}\); together with the affine
  tilde localization instance (wrapped by \cref{lem:isLocalizedModule_tilde_restrict}), it supplies
  the base case of the descent.
\end{lemma}

\begin{lemma}[Compact-open induction]
  \label{lem:compact_open_induction_mathlib}
  \lean{AlgebraicGeometry.compact_open_induction_on}
  \mathlibok
  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Morphisms.QuasiCompact}).}
  Let \(X\) be a scheme and \(P\) a predicate on the opens of \(X\). To prove \(P(S)\) for a
  quasi-compact open \(S\), it suffices to prove \(P(\bot)\) and that \(P(U)\) implies
  \(P(U \cup V)\) for every open \(U\) and every affine open \(V\). This drives the \emph{surj} and
  \emph{exists\_of\_eq} fields of the descent.
\end{lemma}

\begin{lemma}[Sheaf Mayer--Vietoris: the pullback cone over a two-open cover is a limit]
  \label{lem:isLimitPullbackCone_mathlib}
  \lean{TopCat.Sheaf.isLimitPullbackCone}
  \mathlibok
  \textit{Provided by Mathlib
  (\texttt{Mathlib.Topology.Sheaves.SheafCondition.PairwiseIntersections}).}
  For a sheaf \(F\) on a topological space and two opens \(U, V\), the square relating
  \(F(U \cup V)\), \(F(U)\), \(F(V)\), \(F(U \cap V)\) is a pullback (limit). This is the generic
  module Mayer--Vietoris used in the inductive step of the descent.
\end{lemma}

\begin{lemma}[Unique gluing of compatible sections]
  \label{lem:existsUnique_gluing_mathlib}
  \lean{TopCat.Sheaf.existsUnique_gluing}
  \mathlibok
  \textit{Provided by Mathlib
  (\texttt{Mathlib.Topology.Sheaves.SheafCondition.UniqueGluing}); the companion
  \(\mathrm{eq\_of\_locally\_eq'}\) lives in the same file.}
  For a sheaf \(F\) and a family of opens \(\{U_i\}\) with union \(V\), any family of sections
  \(s_i \in F(U_i)\) agreeing on overlaps glues to a unique \(s \in F(V)\); and a section of \(V\)
  is determined by its restrictions to a cover (\(\mathrm{eq\_of\_locally\_eq'}\)). These discharge
  the existence and uniqueness obligations in the inductive step.
\end{lemma}

\begin{lemma}[Section-localization for a quasi-coherent sheaf on $\Spec R$ (G1-core)]
  \label{lem:qcoh_affine_section_localization}

\begin{proof}
  \uses{lem:qcoh_affine_section_localization, lem:isIso_fromTildeΓ_of_isLocalizedModule_restrict}
  G1-core (\cref{lem:qcoh_affine_section_localization}) provides, for every \(f \in R\), that the
  section restriction \(\Gamma(M, \top) \to \Gamma(M, D(f))\) exhibits the target as
  \(\mathrm{IsLocalizedModule}(\mathrm{powers}\,f)\) over \(R\). Feeding this family of localization
  facts into the G1-assemble reduction \cref{lem:isIso_fromTildeΓ_of_isLocalizedModule_restrict}
  yields that the counit \(M.\mathrm{fromTildeΓ}\) is an isomorphism.
\end{proof}

